41: func notAuthorized(c *contextmodel.ReqContext) {
42: 	if c.IsApiRequest() {
43: 		c.WriteErrOrFallback(http.StatusUnauthorized, http.StatusText(http.StatusUnauthorized), c.LookupTokenErr)
44: 		return
45: 	}
46: 
47: 	if !c.UseSessionStorageRedirect {
48: 		writeRedirectCookie(c)
49: 	}
50: 
51: 	if errors.Is(c.LookupTokenErr, authn.ErrTokenNeedsRotation) {
52: 		if !c.UseSessionStorageRedirect {
53: 			c.Redirect(setting.AppSubUrl + "/user/auth-tokens/rotate")
54: 			return
55: 		}
56: 
57: 		c.Redirect(setting.AppSubUrl + "/user/auth-tokens/rotate" + getRedirectToQueryParam(c))
58: 		return
59: 	}
60: 
61: 	if !c.UseSessionStorageRedirect {
62: 		c.Redirect(setting.AppSubUrl + "/login")
63: 		return
64: 	}
65: 
66: 	c.Redirect(setting.AppSubUrl + "/login" + getRedirectToQueryParam(c))
67: }
