353: func getOrgQueryFromRequest(c *contextmodel.ReqContext) (*QueryWithOrg, error) {
354: 	query := &QueryWithOrg{}
355: 
356: 	req, err := CloneRequest(c.Req)
357: 	if err != nil {
358: 		return nil, err
359: 	}
360: 
361: 	if err := web.Bind(req, query); err != nil {
362: 		if err.Error() == "unexpected EOF" {
363: 			return nil, fmt.Errorf("%w: unexpected end of JSON input", ErrInvalidRequestBody)
364: 		}
365: 		return nil, ErrInvalidRequest.Errorf("error parsing request: %w", err)
366: 	}
367: 
368: 	return query, nil
369: }
