71: // addSecurityHeaders adds HTTP(S) response headers that enable various security protections in the client's browser.
72: func addSecurityHeaders(w web.ResponseWriter, cfg *setting.Cfg) {
73: 	if cfg.StrictTransportSecurity {
74: 		strictHeaderValues := []string{fmt.Sprintf("max-age=%v", cfg.StrictTransportSecurityMaxAge)}
75: 		if cfg.StrictTransportSecurityPreload {
76: 			strictHeaderValues = append(strictHeaderValues, "preload")
77: 		}
78: 		if cfg.StrictTransportSecuritySubDomains {
79: 			strictHeaderValues = append(strictHeaderValues, "includeSubDomains")
80: 		}
81: 		w.Header().Set("Strict-Transport-Security", strings.Join(strictHeaderValues, "; "))
82: 	}
83: 
84: 	if cfg.ContentTypeProtectionHeader {
85: 		w.Header().Set("X-Content-Type-Options", "nosniff")
86: 	}
87: 
88: 	if cfg.XSSProtectionHeader {
89: 		w.Header().Set("X-XSS-Protection", "1; mode=block")
90: 	}
91: }
