103: func AddCustomResponseHeaders(cfg *setting.Cfg) web.Handler {
104: 	return func(c *web.Context) {
105: 		c.Resp.Before(func(w web.ResponseWriter) {
106: 			if w.Written() {
107: 				return
108: 			}
109: 
110: 			for header, value := range cfg.CustomResponseHeaders {
111: 				// do not override existing headers
112: 				if w.Header().Get(header) != "" {
113: 					continue
114: 				}
115: 				w.Header().Set(header, value)
116: 			}
117: 		})
118: 	}
