121: func allowCacheControl(rw web.ResponseWriter) bool {
122: 	ccHeaderValues := rw.Header().Values("Cache-Control")
123: 
124: 	if len(ccHeaderValues) == 0 {
125: 		return false
126: 	}
127: 
128: 	foundPrivate := false
129: 	foundPublic := false
130: 	for _, val := range ccHeaderValues {
131: 		strings.Contains(val, "private")
132: 		if strings.Contains(val, "private") {
133: 			foundPrivate = true
134: 		}
135: 		if strings.Contains(val, "public") {
136: 			foundPublic = true
137: 		}
138: 	}
139: 
